solution_code:
#include <iostream>

constexpr int count_digits(int n) {
    if (n < 0) n = -n;
    int count = 0;
    while (n > 0) {
        ++count;
        n /= 10;
    }
    return count;
}

int main() {
    static_assert(count_digits(12345) == 5, "check");
    int x;
    std::cin >> x;
    std::cout << "Digits: " << count_digits(x) << "\n";
    return 0;
}
